// Prepara o prompt para o Claude Haiku analisar a conversa
const sessao = $input.first().json;
const mensagens = sessao.mensagens || [];

const conversa_texto = mensagens.map((m, i) => `[${i+1}] ${m}`).join('\n');

const prompt = `Você é um especialista em análise de conversas comerciais de vendas.

Analise a seguinte conversa comercial e retorne um JSON estruturado:

CONVERSA:
${conversa_texto}

Retorne APENAS um JSON válido (sem markdown) com esta estrutura:
{
  "tipo_venda": "varejo" | "consultiva" | "despertar_desejo" | null,
  "resultado": "converteu" | "perdeu" | "pendente",
  "tom_predominante": "tecnico" | "emocional" | "relacional" | "direto" | "misto",
  "score_qualidade": 0.0 a 10.0,
  "fases": [
    {"fase": "abertura|descoberta|apresentacao|objecao|fechamento", "qualidade": "alta|media|baixa"}
  ],
  "argumentos": [
    {"texto": "...", "efetivo": true|false, "fase": "..."}
  ],
  "objecoes": [
    {"tipo": "preco|prazo|necessidade|confianca|concorrencia|outra", "contornada": true|false, "texto": "..."}
  ],
  "padrao_detectado": "descrição do padrão comportamental principal",
  "flags": ["objecao_ignorada", "tom_inadequado", etc]
}`;

return [{
  json: {
    sessao_id: sessao.sessao_id,
    remote_jid: sessao.remote_jid,
    prompt
  }
}];

