// Extrai e valida o JSON retornado pelo Claude
const sessao_id = $('preparar-prompt').first().json.sessao_id;
const claudeResponse = $input.first().json;

let analise;
try {
  const content = claudeResponse.content?.[0]?.text || '{}';
  analise = JSON.parse(content);
} catch(e) {
  analise = { resultado: 'pendente', score_qualidade: 0, flags: ['parse_error'] };
}

return [{
  json: {
    sessao_id,
    analise,
    tokens_usados: claudeResponse.usage?.input_tokens + claudeResponse.usage?.output_tokens
  }
}];

